dec:
padding-left: var(--doc-list-indent);
  margin: 0;
  list-style-type: none;
  counter-reset: item;

font-family: var(--doc-font-list-item);
  font-size: var(--doc-body-size);
  color: var(--doc-primary-color);
  line-height: var(--doc-body-line-height);
  padding-left: 18pt;
  text-indent: -18pt;
  margin-bottom: 0;
  position: relative;

content: counter(item) ". ";
  counter-increment: item;
  font-weight: 700;
  color: var(--doc-primary-color);
